        "description": "Query to calculate the overlap between consumers and providers.",
        "id": "1TTSB000002Uq9h4AC",
        "name": "QueryOverlap",
        "queryTemplate": {
          "template": "SELECT  Consumer.SegmentId AS Segment_Id__c,  Consumer.SegmentName AS Segment_Name__c,  Provider.SegmentName AS Provider_Segment_Name__c,  Provider.Category AS Provider_Segment_Category__c,  Provider.ParentCategory AS Provider_Segment_Parent_Category__c,  Provider.SegmentSize AS Provider_Segment_Size__c,  Consumer.SegmentSize AS Segment_Size__c,  COUNT(DISTINCT Provider.MemberId) AS Matching_Population_Count__c FROM  Consumer JOIN  Provider ON Consumer.HashedEmailAddress = Provider.HashedEmailAddress GROUP BY Consumer.SegmentId, Consumer.SegmentName, Provider.SegmentName, Provider.Category, Provider.ParentCategory, Provider.SegmentSize, Consumer.SegmentSize HAVING  COUNT(DISTINCT Provider.MemberId) &gt;= :threshold_count",
